function TabIconButton({ tab, active, onClick, badge }) {
  const svgIcon = TabIcons[tab.id];
  return (
    <button onClick={onClick} style={{
      display: "flex", flexDirection: "column", alignItems: "center", gap: 4,
      background: "none", border: "none", cursor: "pointer", padding: "6px 10px",
      flexShrink: 0, fontFamily: "inherit", position: "relative",
    }}>
      <span style={{
        display: "flex", alignItems: "center", justifyContent: "center",
        width: 40, height: 40, borderRadius: "50%",
        background: active ? BRAND.white : "rgba(255,255,255,0.08)",
        border: `2px solid ${active ? BRAND.white : "rgba(255,255,255,0.35)"}`,
        color: active ? BRAND.navy : "rgba(255,255,255,0.75)",
        transition: "all 0.15s",
      }}>
        {svgIcon ? (
          <span style={{ width: 20, height: 20, display: "block" }}>{svgIcon}</span>
        ) : (
          <span style={{ fontSize: 18 }}>{tab.icon}</span>
        )}
      </span>
      {badge > 0 && (
        <span style={{ position: "absolute", top: 2, right: 4, background: "#DC2626", color: "#fff", fontSize: 9, fontWeight: 800, borderRadius: 99, minWidth: 15, height: 15, display: "flex", alignItems: "center", justifyContent: "center", padding: "0 3px", border: `1.5px solid ${BRAND.navy}` }}>
          {badge > 9 ? "9+" : badge}
        </span>
      )}
      <span style={{ fontSize: 9.5, fontWeight: active ? 700 : 500, color: active ? BRAND.white : "rgba(255,255,255,0.65)", whiteSpace: "nowrap" }}>
        {tab.label}
      </span>
    </button>
  );
}

