// ── 3D Piece model ─────────────────────────────────────────────────────────
// Every piece lives in 3D space:
//   px = left-right position (ft from left of house)  → x in plan & front view
//   pz = front-back depth (ft from house wall)        → y in plan view, visible depth in side views
//   py = height off ground (ft)                       → y in front/side elevation views
//   pw = width left-right (ft)
//   pd = depth front-back (ft)
//   ph = height (ft)
// type, steps, label, presetGroup, rotate(plan only), opacity

function uid(){ return Math.random().toString(36).slice(2,9) }

function makePiece(type, px, pz, py, pw, pd, ph, extra={}) {
  return { id:uid(), type, px, pz, py, pw, pd, ph,
    rotate:0, opacity:0.92, steps:4, label:type, presetGroup:null, ...extra }
}

